document.addEventListener("DOMContentLoaded", init);
function init(){ render(); bindGlobal(); restoreDraft(); setDefaults(); updateCalculated(); window.addEventListener('pagehide',()=>saveDraft(false)); document.addEventListener('visibilitychange',()=>{ if(document.hidden) saveDraft(false); }); }
function text(v){ return typeof v === "object" ? v[state.lang] : v; }
function tr(key){ return I18N[state.lang][key] || key; }
function render(){ renderStaticText(); renderNav(); renderSteps(); updateStep(); }
function renderStaticText(){ $$('[data-i18n]').forEach(el => el.textContent = tr(el.dataset.i18n)); document.documentElement.lang = state.lang; }
function renderNav(){ const nav=$('#stepNav'); nav.innerHTML=sections.map((s,i)=>`<button type="button" class="step-link ${i===state.step?'active':''} ${state.completed.has(i)?'complete':''}" data-step="${i}"><span>${i+1}</span><b>${text(s.title)}</b></button>`).join(''); nav.querySelectorAll('button').forEach(button=>button.addEventListener('click',()=>{ const target=Number(button.dataset.step); state.completed.add(state.step); saveDraft(false); state.step=target; clearMessages(); updateStep(); })); }
function renderSteps(){ const root = $('#steps'); root.innerHTML = sections.map((section,i)=>{ const fields=section.fields||[], headerFields=fields.filter(field=>field.header), bodyFields=fields.filter(field=>!field.header); if(i===0) return `<section class="step" data-step-panel="0">${renderStudentWelcome()}<div class="student-search-panel"><div class="student-search-title"><h3>${state.lang==='es'?'Buscar estudiante':'Find student'}</h3><span>${state.lang==='es'?'Código nuevo y año de nacimiento':'New code and birth year'}</span></div><div class="student-search-grid">${renderFields(headerFields)}<div class="student-search-actions"><button type="button" class="lookup-btn" id="profileLookupButton">${state.lang==='es'?'Buscar estudiante':'Find student'}</button><button type="button" class="clear-btn" id="clearStudentButton">${state.lang==='es'?'Limpiar':'Clear'}</button></div></div></div><div class="profile-section-heading"><h2>${state.lang==='es'?'Perfil del estudiante':'Student profile'}</h2><p>${state.lang==='es'?'Complete los datos legales y de contacto del estudiante.':'Complete the student legal and contact details.'}</p></div><div class="grid">${renderFields(bodyFields)}</div></section>`; if(section.review) return `<section class="step" data-step-panel="${i}"><div class="step-header"><div><p class="step-kicker">${i+1} / ${sections.length}</p><h2>${text(section.title)}</h2><p class="step-description">${text(section.desc)}</p></div></div><div id="reviewSummary" class="review-summary"></div><div class="grid review-confirmation">${renderFields(bodyFields)}</div></section>`; return `<section class="step" data-step-panel="${i}"><div class="step-header"><div><p class="step-kicker">${i+1} / ${sections.length}</p><h2>${text(section.title)}</h2>${section.desc?`<p class="step-description">${text(section.desc)}</p>`:''}</div>${headerFields.length?`<div class="step-header-tools">${renderFields(headerFields)}</div>`:''}</div><div class="grid">${renderFields(bodyFields)}${renderRepeaters(section.repeaters||[])}</div></section>`; }).join(''); bindInputs(); }
function renderStudentWelcome(){ if(state.lang==='es') return `<section class="welcome-panel"><div class="welcome-title"><div><p class="welcome-eyebrow">Casa de las Estrellas</p><h2>Bienvenidos al formulario de actualización estudiantil</h2></div></div><p>Este formulario permite actualizar, completar o confirmar la información actual de sus hijos.</p><div class="documents-note"><strong>Tenga a mano:</strong><span>identificación del estudiante, certificado de nacimiento, fotografía reciente, identificaciones de los tutores, carné de vacunas o declaración jurada y documentos médicos o académicos cuando correspondan.</span></div></section>`; return `<section class="welcome-panel"><div class="welcome-title"><div><p class="welcome-eyebrow">Casa de las Estrellas</p><h2>Welcome to the student information update form</h2></div></div><p>Use this form to update, complete or confirm your children's current information.</p><div class="documents-note"><strong>Have ready:</strong><span>student ID, birth certificate, recent photo, guardian IDs, vaccination record or affidavit, and applicable medical or academic documents.</span></div></section>`; }
function renderFields(fields){ return fields.map(field=>renderField(field)).join(''); }
function renderField(field, prefix=""){ const conditionValues=field.conditional?(field.conditional.values||[field.conditional.value]).filter(Boolean):[]; const conditionalField=field.conditional?`${prefix}${field.conditional.field}`:''; const cond=field.conditional?` data-conditional-field="${conditionalField}" data-conditional-values="${conditionValues.join('|')}" ${field.conditional.includes?'data-conditional-includes="true"':''}`:''; if(field.type==="info") return `<div class="info-box ${field.conditional?'conditional hidden':''}"${cond}>${text(field.text)}</div>`; const name=prefix+field.name; const dynamicallyRequired=field.required||field.requiredForNew; const req=dynamicallyRequired?`<span class="required">*</span>`:''; const hint=field.type==='date'?`<span class="hint">${tr('dateFormatHint')}</span>`:field.type==='multiselect'?`<span class="hint">${state.lang==='es'?'Puede seleccionar varias opciones.':'You may select multiple options.'}</span>`:field.type==='searchselect'?`<span class="hint">${state.lang==='es'?'Puede escribir para buscar una opción.':'Type to search for an option.'}</span>`:field.hintKey?`<span class="hint">${tr(field.hintKey)}</span>`:field.hint?`<span class="hint">${text(field.hint)}</span>`:''; const stored=field.type==='file'?`<span class="existing-document${state.existingDocuments.has(name)?' visible':''}">${existingDocumentText(name)}</span>`:''; const cls=`field ${field.full||["textarea","file","checkbox","radio","signature","profile","multiselect","segmented"].includes(field.type)?'full':''} ${field.conditional?'conditional hidden':''}`; const label=["checkbox","segmented"].includes(field.type)?"":`<label for="${name}">${text(field.label)} ${req}</label>`; return `<div class="${cls}" data-field-wrap="${name}" ${field.requiredForNew?'data-required-for-new="true"':''}${cond}>${label}${renderControl(field,name)}${stored}${hint}<span class="error-text" data-error-for="${name}"></span></div>`; }
function existingDocumentText(name){ const names=state.existingDocumentDetails.filter(item=>item.field===name).map(item=>item.name).filter(Boolean); return state.lang==='es'?`Ya guardado en Drive${names.length?': '+names.join(', '):''}`:`Already saved in Drive${names.length?': '+names.join(', '):''}`; }
function renderControl(field,name){ if(field.type==="textarea") return `<textarea id="${name}" name="${name}" ${field.required?'required':''}></textarea>`; if(field.type==="select") return `<select id="${name}" name="${name}" ${field.required?'required':''}><option value="">${tr('select')}</option>${field.options.map(o=>`<option value="${o.value}">${text(o)}</option>`).join('')}</select>`; if(field.type==="searchselect"){ const listId=`list-${slug(name)}`; return `<input id="${name}" name="${name}" type="text" list="${listId}" autocomplete="off" ${field.required?'required':''}><datalist id="${listId}">${field.options.map(o=>`<option value="${o.value}">${text(o)}</option>`).join('')}</datalist>`; } if(field.type==="multiselect") return `<div class="multi-options">${field.options.map((o,index)=>`<label class="check-card"><input id="${name}-${index}" name="${name}" type="checkbox" value="${o.value}"><span>${text(o)}</span></label>`).join('')}</div>`; if(field.type==="segmented") return `<div class="options segmented-options"><span class="sr-only">${text(field.label)}</span>${field.options.map((o,index)=>`<label class="choice"><input type="radio" name="${name}" value="${o.value}" ${field.required?'required':''} ${index===0?'checked':''}> ${text(o)}</label>`).join('')}</div>`; if(field.type==="systemstatus") return `<input id="${name}" name="${name}" type="hidden"><div class="system-status" id="studentTypeStatus">${state.lang==='es'?'Por determinar':'To be determined'}</div>`; if(field.type==="date") return renderDateControl(name,field.required,field.readonly); if(field.type==="detected") return `<input id="${name}" name="${name}" type="hidden" ${field.required?'required':''}><input id="${name}Display" type="text" readonly aria-label="${text(field.label)}">`; if(field.type==="profile") return `<input id="${name}" name="${name}" type="text" placeholder="${tr('profilePlaceholder')}" autocomplete="off" maxlength="12" pattern="[A-Z]{2}[0-9]{2}[A-Z][0-9]{2}(-[0-9]{2})?" ${field.required?'required':''}>`; if(field.type==="numbertext") return `<input id="${name}" name="${name}" type="text" inputmode="numeric" pattern="[0-9]*" ${field.required?'required':''} ${field.validate?`data-validate="${field.validate}"`:''}>`; if(field.type==="signature") return `<div class="signature-pad"><canvas id="signatureCanvas" width="900" height="260" aria-label="${text(field.label)}"></canvas><input id="${name}" name="${name}" type="hidden" ${field.required?'required':''}><button type="button" class="remove-btn" id="clearSignature">${tr('clearSignature')}</button></div>`; if(field.type==="radio") return `<div class="options">${field.options.map(o=>`<label class="choice"><input type="radio" name="${name}" value="${o.value}" ${field.required?'required':''}> ${text(o)}</label>`).join('')}</div>`; if(field.type==="checkbox") return `<label class="check-card"><input id="${name}" name="${name}" type="checkbox" value="yes" ${field.required?'required':''}> <span>${text(field.label)} ${field.required?'<span class="required">*</span>':''}</span></label>`; if(field.type==="file") return `<input id="${name}" name="${name}" type="file" ${field.multiple?'multiple':''} ${field.required?'required':''} data-category="${field.category||'08_Otros documentos'}">`; return `<input id="${name}" name="${name}" type="${field.type}" ${field.required?'required':''} ${field.readonly?'readonly':''} ${field.placeholder?`placeholder="${field.placeholder}"`:''} ${field.min?`min="${field.min}"`:''} ${field.max?`max="${field.max}"`:''} ${field.validate?`data-validate="${field.validate}"`:''}>`; }
function renderDateControl(name,required,readonly=false){ const months=state.lang==='es'?['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre']:['January','February','March','April','May','June','July','August','September','October','November','December']; const maxYear=new Date().getFullYear()+15; const years=Array.from({length:maxYear-1899},(_,i)=>maxYear-i), locked=readonly?'disabled':''; return `<div class="date-select" data-date-control="${name}"><input id="${name}" name="${name}" type="hidden" data-date-value ${required?'required':''}><select data-date-part="day" aria-label="${state.lang==='es'?'Día':'Day'}" ${locked}><option value="">${state.lang==='es'?'Día':'Day'}</option>${Array.from({length:31},(_,i)=>`<option value="${String(i+1).padStart(2,'0')}">${i+1}</option>`).join('')}</select><select data-date-part="month" aria-label="${state.lang==='es'?'Mes':'Month'}" ${locked}><option value="">${state.lang==='es'?'Mes':'Month'}</option>${months.map((month,i)=>`<option value="${String(i+1).padStart(2,'0')}">${month}</option>`).join('')}</select><select data-date-part="year" aria-label="${state.lang==='es'?'Año':'Year'}" ${locked}><option value="">${state.lang==='es'?'Año':'Year'}</option>${years.map(year=>`<option value="${year}">${year}</option>`).join('')}</select></div>`; }
function renderRepeaters(repeaters){ return repeaters.map(rep=>{ const values=rep.conditional?.values||[]; const cond=rep.conditional?` conditional hidden data-conditional-field="${rep.conditional.field}" data-conditional-values="${values.join('|')}"`:''; const count=Math.max(state.repeaters[rep.name]||0,rep.min||1); return `<div class="repeater${cond}" data-repeater="${rep.name}">${Array.from({length: count},(_,i)=>renderRepeaterItem(rep,i)).join('')}<button class="add-btn" type="button" data-add-repeater="${rep.name}">${tr(rep.addKey)}</button></div>`; }).join(''); }
function renderRepeaterItem(rep,i){ return `<div class="repeater-item" data-repeater-item="${rep.name}.${i}"><div class="repeater-head"><strong>${text(sections.find(s=>(s.repeaters||[]).some(r=>r.name===rep.name)).title)} ${i+1}</strong>${i >= (rep.min||1) ? `<button class="remove-btn" type="button" data-remove-repeater="${rep.name}" data-index="${i}">${tr('remove')}</button>` : ''}</div><div class="grid">${rep.fields.map(field=>renderField(field,`${rep.name}.${i}.`)).join('')}</div></div>`; }
function bindGlobal(){ $$('.lang-btn').forEach(btn=>btn.addEventListener('click',()=>{ state.lang=btn.dataset.lang; $$('.lang-btn').forEach(b=>b.classList.toggle('active',b===btn)); const data = collectValues(false); render(); fillValues(data); updateCalculated(); scheduleDraftSave(); })); $('#prevBtn').addEventListener('click',()=>{ saveDraft(false); state.step=Math.max(0,state.step-1); clearMessages(); updateStep(); }); $('#nextBtn').addEventListener('click',()=>{ state.completed.add(state.step); saveDraft(false); state.step=Math.min(sections.length-1,state.step+1); clearMessages(); updateStep(); }); $('#saveBtn').addEventListener('click',()=>saveDraft(true)); $('#admissionForm').addEventListener('input',scheduleDraftSave); $('#admissionForm').addEventListener('change',scheduleDraftSave); $('#admissionForm').addEventListener('submit',()=>saveDraft(false),true); $('#admissionForm').addEventListener('submit',submitForm); }
function bindInputs(){ $$('input,select,textarea').forEach(el=>{ el.addEventListener('input',()=>{ if(el.dataset.validate==='documentId') el.value=el.value.replace(/\D/g,''); updateCalculated(); updateConditionals(); clearError(el.name); }); el.addEventListener('change',()=>{ if(el.dataset.validate==='documentId') el.value=el.value.replace(/\D/g,''); updateCalculated(); updateConditionals(); clearError(el.name); }); }); $$('[data-date-control]').forEach(control=>control.querySelectorAll('select').forEach(select=>select.addEventListener('change',()=>{ syncDateControl(control); updateCalculated(); clearError(control.dataset.dateControl); }))); $$('[name$=".source"]').forEach(select=>select.addEventListener('change',()=>populateEmergencyContact(select))); $$('[data-add-repeater]').forEach(btn=>btn.addEventListener('click',()=>{ const data=collectValues(false); state.repeaters[btn.dataset.addRepeater]=(state.repeaters[btn.dataset.addRepeater]||1)+1; render(); fillValues(data); })); $$('[data-remove-repeater]').forEach(btn=>btn.addEventListener('click',()=>{ const data=collectValues(false); const name=btn.dataset.removeRepeater; Object.keys(data).forEach(k=>{ if(k.startsWith(name+'.')) delete data[k]; }); state.repeaters[name]=Math.max(0,(state.repeaters[name]||1)-1); render(); fillValues(data); })); $('#profileLookupButton')?.addEventListener('click',lookupSelectedProfile); $('#clearStudentButton')?.addEventListener('click',clearStudentForm); const code=$('[name="studentLookupCode"]'); code?.addEventListener('input',()=>{ code.value=code.value.toUpperCase().replace(/[^A-Z0-9-]/g,'').slice(0,12); setVal('studentId',code.value); }); code?.addEventListener('change',()=>setVal('studentId',code.value)); code?.addEventListener('keydown',event=>{ if(event.key==='Enter'){ event.preventDefault(); lookupSelectedProfile(); } }); bindSignaturePad(); updateConditionals(); }
function populateEmergencyContact(select){ const prefix=select.name.replace(/source$/,''); const source=select.value; if(source==='Tutor legal registrado'){ const base='legalGuardians.0.'; const first=$(`[name="${base}firstName"]`)?.value||'', last1=$(`[name="${base}lastName1"]`)?.value||'', last2=$(`[name="${base}lastName2"]`)?.value||''; setVal(prefix+'name',[first,last1,last2].filter(Boolean).join(' ')); setVal(prefix+'relationship',$(`[name="${base}relationship"]`)?.value||'Tutor legal'); setVal(prefix+'phoneCode',$(`[name="${base}phoneCode"]`)?.value||'+506'); setVal(prefix+'phone',$(`[name="${base}phone"]`)?.value||''); setVal(prefix+'email',$(`[name="${base}email"]`)?.value||''); } }
function clearStudentForm(){ localStorage.removeItem(CONFIG.LOCAL_STORAGE_KEY); $('#admissionForm').reset(); state.completed.clear(); state.studentSince=''; state.existingDocuments.clear(); state.existingDocumentDetails=[]; state.signatureDataUrl=null; state.step=0; render(); setDefaults(); clearMessages(); $('#draftStatus').textContent=''; }
function syncDateControl(control){ const day=control.querySelector('[data-date-part="day"]').value, month=control.querySelector('[data-date-part="month"]').value, year=control.querySelector('[data-date-part="year"]').value; const hidden=control.querySelector('[data-date-value]'); if(!day||!month||!year){ hidden.value=''; return; } const iso=`${year}-${month}-${day}`; const date=new Date(`${iso}T12:00:00`); hidden.value=date.getFullYear()===Number(year)&&date.getMonth()+1===Number(month)&&date.getDate()===Number(day)?iso:''; }
function setDateControl(name,value){ const control=$(`[data-date-control="${CSS.escape(name)}"]`); if(!control) return false; const iso=normalizeDateValue(value); const match=iso.match(/^(\d{4})-(\d{2})-(\d{2})$/); control.querySelector('[data-date-part="day"]').value=match?match[3]:''; control.querySelector('[data-date-part="month"]').value=match?match[2]:''; control.querySelector('[data-date-part="year"]').value=match?match[1]:''; control.querySelector('[data-date-value]').value=match?iso:''; return true; }
function updateStep(){ $$('.step').forEach((p,i)=>p.classList.toggle('active',i===state.step)); renderNav(); $('#progressLabel').textContent = `${state.step+1} / ${sections.length}`; $('#progressTitle').textContent = text(sections[state.step].title); $('#progressBar').style.width = `${((state.step+1)/sections.length)*100}%`; $('#prevBtn').classList.toggle('hidden',state.step===0); $('#nextBtn').classList.toggle('hidden',state.step===sections.length-1); $('#submitBtn').classList.toggle('hidden',state.step!==sections.length-1); if(sections[state.step]?.review) renderReviewSummary(); window.scrollTo({top:0,behavior:'smooth'}); }
function renderReviewSummary(){ const root=$('#reviewSummary'); if(!root) return; const data=collectValues(false); root.innerHTML=sections.filter(section=>!section.review).map((section,index)=>{ const rows=(section.fields||[]).filter(field=>field.name&&!field.header).map(field=>{ let value=data[field.name]; const file=$(`[name="${CSS.escape(field.name)}"]`); if(file?.type==='file') value=[...file.files].map(item=>item.name).join(', '); if(Array.isArray(value)) value=value.join(', '); if(value==='yes') value=state.lang==='es'?'Sí':'Yes'; if(value==='no') value=state.lang==='es'?'No':'No'; return value?`<div><dt>${text(field.label)}</dt><dd>${escapeHtml(value)}</dd></div>`:''; }).join(''); return rows?`<article class="review-card"><header><h3>${text(section.title)}</h3><button type="button" data-edit-step="${index}">${state.lang==='es'?'Editar':'Edit'}</button></header><dl>${rows}</dl></article>`:''; }).join('')||`<p>${state.lang==='es'?'Complete las secciones anteriores para ver el resumen.':'Complete previous sections to see the summary.'}</p>`; $$('[data-edit-step]').forEach(button=>button.addEventListener('click',()=>{ state.step=Number(button.dataset.editStep); updateStep(); })); }
function escapeHtml(value){ return String(value).replace(/[&<>"']/g,char=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[char])); }
function updateCalculated(){ const first=$('[name="firstName"]')?.value.trim()||'', last1=$('[name="lastName1"]')?.value.trim()||'', last2=$('[name="lastName2"]')?.value.trim()||''; const full=[first,last1,last2].filter(Boolean).join(' '); const bd=$('[name="birthDate"]')?.value; if(bd) setVal('age',calcAge(bd)); const today=new Date().toISOString().slice(0,10); if(!$('[name="submissionDate"]')?.value) setVal('submissionDate',today); if(!$('[name="schoolPeriod"]')?.value) setVal('schoolPeriod',currentSchoolYear()); const type=$('[name="entryType"]')?.value||''; const automatic=type==='existing'?(state.lang==='es'?`Estudiante actual${state.studentSince?` · Desde ${state.studentSince}`:''}`:`Current student${state.studentSince?` · Since ${state.studentSince}`:''}`):type==='new'?(state.lang==='es'?'Estudiante nuevo':'New student'):(state.lang==='es'?'Por determinar':'To be determined'); const status=$('#studentStatus'), detail=$('#studentTypeStatus'); if(status) status.textContent=automatic; if(detail) detail.innerHTML=`<strong>${automatic}</strong>${full?`<span>${escapeHtml(full)}</span>`:''}`; updateExistingDocumentIndicators(); }
function updateExistingDocumentIndicators(){ $$('input[type="file"]').forEach(input=>{ const indicator=input.parentElement.querySelector('.existing-document'); if(!indicator) return; indicator.classList.toggle('visible',state.existingDocuments.has(input.name)); indicator.textContent=existingDocumentText(input.name); }); }
function currentSchoolYear(){ const now = new Date(); const start = now.getFullYear(); return `${start}-${start + 1}`; }
function setDefaults(){ updateCalculated(); [['currentProvince','Guanacaste'],['currentCanton','Nicoya'],['currentDistrict','Nosara'],['legalGuardians.0.phoneCode','+506']].forEach(([name,value])=>{ if(!$(`[name="${name}"]`)?.value) setVal(name,value); }); }
function setVal(name,val){ if(setDateControl(name,val)) return; const els=$$(`[name="${CSS.escape(name)}"]`); if(!els.length) return; if(els[0].type==='radio'){ els.forEach(el=>el.checked=el.value===val); return; } if(els[0].multiple&&Array.isArray(val)){ [...els[0].options].forEach(option=>option.selected=val.includes(option.value)); return; } if(!els[0].matches(':focus')) els[0].value=val??''; }
function mirror(from,to){ const a=$(`[name="${from}"]`), b=$(`[name="${to}"]`); if(a&&b&&!b.value) b.value=a.value; }
function calcAge(date){ const d=new Date(`${date}T12:00:00`), n=new Date(); let months=(n.getFullYear()-d.getFullYear())*12+n.getMonth()-d.getMonth(); if(n.getDate()<d.getDate()) months--; months=Math.max(0,months); const years=Math.floor(months/12), remaining=months%12; return state.lang==='es'?`${years} años, ${remaining} meses`:`${years} years, ${remaining} months`; }
function docStatus(date){ if(!date) return state.lang==='es'?"Sin fecha registrada":"No date recorded"; const d=new Date(date), n=new Date(); const days=(d-n)/(1000*60*60*24); if(days<0) return state.lang==='es'?"Vencido":"Expired"; if(days<=90) return state.lang==='es'?"Próximo a vencer":"Expiring soon"; return state.lang==='es'?"Vigente":"Valid"; }
function updateConditionals(){ $$('[data-conditional-field]').forEach(w=>{ const field=w.dataset.conditionalField, accepted=(w.dataset.conditionalValues||'').split('|'); const els=$$(`[name="${CSS.escape(field)}"]`); const checkedValues=els.filter(el=>el.type==='checkbox'&&el.checked).map(el=>el.value); const checked=els.find(el=>el.type==='radio'&&el.checked); const selected=checkedValues.length?checkedValues:els[0]?.multiple?[...els[0].selectedOptions].map(option=>option.value):[checked?checked.value:els[0]?.value]; const visible=accepted.some(value=>selected.includes(value)); w.classList.toggle('hidden',!visible); }); }
function collectValues(includeFiles=true){ const data={}; const fd=new FormData($('#admissionForm')); for(const [k,v] of fd.entries()){ if(v instanceof File){ continue; } if(data[k]) data[k]=Array.isArray(data[k])?[...data[k],v]:[data[k],v]; else data[k]=v; } $$('input[type="checkbox"]').forEach(el=>{ if(!data[el.name]) data[el.name]=el.checked ? 'yes' : ''; }); return data; }
function fillValues(data){ Object.entries(data).forEach(([name,val])=>{ if(setDateControl(name,val)) return; const els=$$(`[name="${CSS.escape(name)}"]`); if(!els.length) return; if(els[0].type==='radio') els.forEach(e=>e.checked=e.value===val); else if(els[0].type==='checkbox'){ const selected=Array.isArray(val)?val:[val]; els.forEach(e=>e.checked=els.length===1?val==='yes':selected.includes(e.value)); } else if(els[0].multiple){ const selected=Array.isArray(val)?val:[val]; Array.from(els[0].options).forEach(option=>option.selected=selected.includes(option.value)); } else if(els[0].type!=='file') els[0].value=val??''; }); updateCalculated(); updateConditionals(); }
function validateStep(i,show){ clearMessages(); let ok=true; const panel=$(`[data-step-panel="${i}"]`); const entryType=$('[name="entryType"]')?.value||'', isNew=entryType==='new'; panel.querySelectorAll('.field:not(.hidden)').forEach(w=>{ const control=w.querySelector('input,select,textarea'); if(!control) return; const requiredForNew=w.dataset.requiredForNew==='true'&&isNew; if(control.type==='file'){ const alreadyStored=state.existingDocuments.has(control.name); if((control.required||requiredForNew)&&control.files.length===0&&!alreadyStored) ok=fieldError(control.name,tr('required'),show)&&ok; [...control.files].forEach(file=>{ if(file.size>CONFIG.MAX_FILE_MB*1024*1024) ok=fieldError(control.name,tr('fileTooLarge'),show)&&ok; }); return; } if(control.type==='radio'){ const any=panel.querySelector(`[name="${control.name}"]:checked`); if((control.required||requiredForNew)&&!any) ok=fieldError(control.name,tr('required'),show)&&ok; return; } if(control.type==='checkbox'){ const sameName=[...panel.querySelectorAll(`[name="${CSS.escape(control.name)}"]`)], any=sameName.some(item=>item.checked); if((control.required||requiredForNew)&&!any) ok=fieldError(control.name,tr('required'),show)&&ok; return; } if(control.dataset.dateValue){ const parts=[...w.querySelectorAll('[data-date-part]')], partiallyFilled=parts.some(part=>part.value); if((control.required||requiredForNew||partiallyFilled)&&!control.value) ok=fieldError(control.name,tr('dateFormatError'),show)&&ok; } else if((control.required||requiredForNew)&&!String(control.value).trim()) ok=fieldError(control.name,tr('required'),show)&&ok; if(control.dataset.validate==='email'||control.type==='email'){ if(control.value&&!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(control.value)) ok=fieldError(control.name,tr('emailError'),show)&&ok; } if(control.dataset.validate==='phone'||control.type==='tel'){ const digits=String(control.value).replace(/\D/g,''); if(control.value&&(digits.length<7||digits.length>15)) ok=fieldError(control.name,tr('phoneError'),show)&&ok; } if(control.dataset.validate==='documentId'&&control.value&&!validDocumentId(control)) ok=fieldError(control.name,tr('idError'),show)&&ok; }); if(show&&!ok) showMessage(tr('fixErrors')); return ok; }
function validDocumentId(control){ return /^\d{5,15}$/.test(String(control.value).replace(/\D/g,'')); }
function fieldError(name,msg,show){ if(show){ const w=$(`[data-field-wrap="${CSS.escape(name)}"]`); if(w) w.classList.add('invalid'); const e=$(`[data-error-for="${CSS.escape(name)}"]`); if(e) e.textContent=msg; } return false; }
function clearError(name){ const w=$(`[data-field-wrap="${CSS.escape(name)}"]`); if(w) w.classList.remove('invalid'); const e=$(`[data-error-for="${CSS.escape(name)}"]`); if(e) e.textContent=''; }
function clearMessages(){ $('#formMessages').innerHTML=''; }
function showMessage(msg,kind='error'){ $('#formMessages').innerHTML=`<div class="alert ${kind==='ok'?'ok':''}">${msg}</div>`; }
function scheduleDraftSave(){ clearTimeout(draftTimer); draftTimer=setTimeout(()=>saveDraft(false),700); }
function saveDraft(showConfirmation=true){ const data=collectValues(false); const draft={data,repeaters:state.repeaters,lang:state.lang,step:state.step,completed:[...state.completed],studentSince:state.studentSince,existingDocuments:[...state.existingDocuments],existingDocumentDetails:state.existingDocumentDetails,signatureDataUrl:state.signatureDataUrl,savedAt:new Date().toISOString()}; localStorage.setItem(CONFIG.LOCAL_STORAGE_KEY,JSON.stringify(draft)); const status=$('#draftStatus'); if(status) status.textContent=tr('autoSaved'); if(showConfirmation) showMessage(tr('saved'),'ok'); }
function restoreDraft(){ try{ const draft=JSON.parse(localStorage.getItem(CONFIG.LOCAL_STORAGE_KEY)||'null'); if(draft){ state.repeaters=draft.repeaters||state.repeaters; state.lang=draft.lang||state.lang; state.step=Number.isInteger(draft.step)?draft.step:0; state.completed=new Set(draft.completed||[]); state.studentSince=draft.studentSince||''; state.existingDocuments=new Set(draft.existingDocuments||[]); state.existingDocumentDetails=draft.existingDocumentDetails||[]; state.signatureDataUrl=draft.signatureDataUrl||null; $$('.lang-btn').forEach(b=>b.classList.toggle('active',b.dataset.lang===state.lang)); render(); fillValues(draft.data||{}); updateStep(); const status=$('#draftStatus'); if(status) status.textContent=tr('autoSaved'); } }catch(e){} }
async function submitForm(e){ e.preventDefault(); clearMessages(); let ok=true; for(let i=0;i<sections.length;i++){ if(!validateStep(i,false)){ ok=false; state.step=i; updateStep(); validateStep(i,true); break; } } if(!ok) return; if(!businessRules()) return; if(CONFIG.APPS_SCRIPT_URL.includes('PASTE_YOUR')){ showMessage(state.lang==='es'? 'Pegue primero la URL del Web App de Apps Script en app.js.' : 'Paste the Apps Script Web App URL in app.js first.'); return; } $('#submitBtn').disabled=true; $('#submitBtn').textContent=tr('loading'); try{ const payload={language:state.lang, submittedAt:new Date().toISOString(), data:collectValues(false), files:await collectFiles()}; const res=await fetch(CONFIG.APPS_SCRIPT_URL,{method:'POST',body:JSON.stringify(payload),headers:{'Content-Type':'text/plain;charset=utf-8'}}); const json=await res.json(); if(!json.ok) throw new Error(json.error||'Submission failed'); localStorage.removeItem(CONFIG.LOCAL_STORAGE_KEY); $('#admissionForm').classList.add('hidden'); $('#successPanel').classList.remove('hidden'); $('#successMeta').textContent=json.studentId ? `ID: ${json.studentId}` : ''; $('#successPanel').focus(); }catch(err){ console.error(err); showMessage(tr('sendError')); }finally{ $('#submitBtn').disabled=false; $('#submitBtn').textContent=tr('submit'); } }
function businessRules(){ const data=collectValues(false); if(!data.householdSelection){ state.step=sections.findIndex(s=>s.id==='household'); updateStep(); showMessage(state.lang==='es'?'Seleccione una opción en personas adicionales.':'Select an option for additional people.'); return false; } if((state.repeaters.emergencyContacts||0)<2){ state.step=sections.findIndex(s=>s.id==='emergency'); updateStep(); showMessage(tr('emergencyError')); return false; } if(data.entryType==='new'&&data.academicMode==='na'){ state.step=sections.findIndex(s=>s.id==='academic'); updateStep(); showMessage(state.lang==='es'?'La información académica es obligatoria para estudiantes nuevos.':'Academic information is required for new students.'); return false; } if(data.reviewConfirmed!=='yes'){ state.step=sections.findIndex(s=>s.id==='review'); updateStep(); showMessage(tr('fixErrors')); return false; } return true; }
async function collectFiles(){ const files=[]; for(const input of $$('input[type="file"]')){ for(const file of input.files){ files.push({field:input.name, category:input.dataset.category||'08_Otros documentos', name:file.name, mimeType:file.type||'application/octet-stream', size:file.size, base64:await fileToBase64(file)}); } } const canvas=$('#signatureCanvas'); if(canvas && $('[name="digitalSignature"]')?.value){ const dataUrl=state.signatureDataUrl||canvas.toDataURL('image/png'); files.push({field:'digitalSignatureFile',category:'05_Autorizaciones',name:'firma-digital.png',mimeType:'image/png',size:dataUrl.length,base64:dataUrl.split(',')[1]}); } return files; }
function fileToBase64(file){ return new Promise((resolve,reject)=>{ const reader=new FileReader(); reader.onload=()=>resolve(String(reader.result).split(',')[1]); reader.onerror=reject; reader.readAsDataURL(file); }); }
function lookupSelectedProfile(){ const code=String($('[name="studentLookupCode"]')?.value||'').trim().toUpperCase(); const birthYear=String($('[name="lookupBirthYear"]')?.value||'').trim(); if(!/^[A-Z]{2}\d{2}[A-Z]\d{2}(?:-\d{2})?$/.test(code)){ fieldError('studentLookupCode',state.lang==='es'?'Ingrese el código nuevo, por ejemplo NN20S21.':'Enter the new code, for example NN20S21.',true); showMessage(tr('lookupMissing')); return; } if(!birthYear){ fieldError('lookupBirthYear',tr('required'),true); showMessage(tr('fixErrors')); return; } lookupStudent(code,birthYear); }
async function lookupStudent(studentId,birthYear){ if(!studentId){ showMessage(tr('lookupMissing')); return; } if(CONFIG.APPS_SCRIPT_URL.includes('PASTE_YOUR')){ showMessage(state.lang==='es'? 'Configure la URL de Apps Script para buscar estudiantes.' : 'Configure the Apps Script URL to find students.'); return; } try{ const json=await apiRequest({action:'lookupStudent',studentId,verificationBirthYear:birthYear}); if(json.ok&&json.data){ state.studentSince=String(json.data.studentSince||''); state.existingDocuments=new Set(json.data.existingDocumentFields||[]); fillValues(json.data); setVal('studentLookupCode',studentId); setVal('lookupBirthYear',birthYear); setVal('studentId',json.data.studentId||studentId); setVal('entryType','existing'); updateCalculated(); showMessage(tr('lookupFound'),'ok'); } else if(json.reason==='verification_failed'){ showMessage(tr('lookupVerifyError')); } else { state.studentSince=''; state.existingDocuments.clear(); setVal('studentLookupCode',studentId); setVal('lookupBirthYear',birthYear); setVal('studentId',studentId); setVal('entryType','new'); updateCalculated(); showMessage(tr('lookupMissing'),'ok'); } }catch(e){ showMessage(state.lang==='es'?'No fue posible consultar el registro. Intente nuevamente.':'The record could not be checked. Please try again.'); } }
function cleanGradeLabel(value){ return String(value||'').replace(/^0?9\s+/,'').replace(/^0\s+/,'').trim(); }
async function apiRequest(payload){ const res=await fetch(CONFIG.APPS_SCRIPT_URL,{method:'POST',body:JSON.stringify(payload),headers:{'Content-Type':'text/plain;charset=utf-8'}}); return res.json(); }
function bindSignaturePad(){ const canvas=$('#signatureCanvas'); const hidden=$('[name="digitalSignature"]'); if(!canvas||!hidden) return; const ctx=canvas.getContext('2d'); ctx.lineWidth=4; ctx.lineCap='round'; ctx.strokeStyle='#155e70'; if(state.signatureDataUrl){ const image=new Image(); image.onload=()=>ctx.drawImage(image,0,0,canvas.width,canvas.height); image.src=state.signatureDataUrl; hidden.value='signed'; } let drawing=false; const point=e=>{ const r=canvas.getBoundingClientRect(), p=e.touches?.[0]||e; return {x:(p.clientX-r.left)*(canvas.width/r.width),y:(p.clientY-r.top)*(canvas.height/r.height)}; }; const start=e=>{ drawing=true; const p=point(e); ctx.beginPath(); ctx.moveTo(p.x,p.y); e.preventDefault(); }; const move=e=>{ if(!drawing) return; const p=point(e); ctx.lineTo(p.x,p.y); ctx.stroke(); hidden.value='signed'; clearError('digitalSignature'); e.preventDefault(); }; const stop=()=>{ if(drawing){ drawing=false; state.signatureDataUrl=canvas.toDataURL('image/png'); scheduleDraftSave(); } }; canvas.addEventListener('pointerdown',start); canvas.addEventListener('pointermove',move); window.addEventListener('pointerup',stop); $('#clearSignature')?.addEventListener('click',()=>{ ctx.clearRect(0,0,canvas.width,canvas.height); hidden.value=''; state.signatureDataUrl=null; scheduleDraftSave(); }); }
function normalizeDateValue(value){ if(!value) return ''; if(typeof value==='number'&&value>20000){ const date=new Date(Date.UTC(1899,11,30)+value*86400000); return date.toISOString().slice(0,10); } const text=String(value); const iso=text.match(/^\d{4}-\d{2}-\d{2}/); if(iso) return iso[0]; const date=new Date(value); return Number.isNaN(date.getTime())?'':date.toISOString().slice(0,10); }
